import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"55. Rest Period After Overtime Recall Ten Hour Break","description":"","frontmatter":{"title":"55. Rest Period After Overtime Recall Ten Hour Break","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","rosters","breaks"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/55-rest-period-after-overtime-recall-ten-hour-break.md","filePath":"ebas/allied-health/hours-of-work/55-rest-period-after-overtime-recall-ten-hour-break.md"}'),s={name:"ebas/allied-health/hours-of-work/55-rest-period-after-overtime-recall-ten-hour-break.md"};function l(i,e,n,h,u,d){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_55-rest-period-after-overtime-recall-ten-hour-break" tabindex="-1">55. Rest Period After Overtime Recall Ten Hour Break <a class="header-anchor" href="#_55-rest-period-after-overtime-recall-ten-hour-break" aria-label="Permalink to &quot;55. Rest Period After Overtime Recall Ten Hour Break&quot;">​</a></h1><p><strong>55.1</strong> When overtime, including recall, is necessary the Employee will have at least 10 consecutive hours off duty between all bodies of work, subject to subclauses 55.3 and 55.4 below.</p><p><strong>55.2</strong> Release from duty An Employee who works so much overtime or recall between the end of the Employee&#39;s previous ordinary hours and the start of the next period of ordinary hours, that the Employee would not have at least 10 consecutive hours off duty between the end of the overtime or recall and the start of the next rostered period of ordinary hours will, subject to this clause 55, be released after completion of such overtime or recall worked until the Employee has had 10 consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>55.3</strong> Work without release from duty</p><p><strong>(a)</strong> If, on the instructions of the Employer, an Employee resumes or continues work without 10 successive hours off duty the Employee will be paid at the rate of double time until the Employee is released from duty for such rest period and the Employee will then be entitled to be absent until the Employee has had 10 consecutive hours off duty without loss of pay for rostered hours occurring during such absence.</p><p><strong>(b)</strong> If an Employee resumes work of the Employee&#39;s own volition, overtime will be calculated in accordance with <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">clause 52</a> (Overtime). An Employee who resumes work voluntarily will be entitled without loss of pay to attend to ablution and</p><p>sustenance matters. The Employee will not resume work of their own volition where doing so will cause a significant occupational health and safety risk.</p><p><strong>55.4</strong> Exception – recall work continuous with next rostered shift</p><p><strong>(a)</strong> Subclauses 55.1 to 55.3 do not apply where:</p><p><strong>(i)</strong> despite the recall, the Employee has had at least 10 consecutive hours off duty between their rostered periods of ordinary duty;</p><p><strong>(ii)</strong> the period of recall is continuous with the next period of ordinary hours; and</p><p><strong>(iii)</strong> the Employee does not work more than two (2) hours recall.</p><p><strong>(b)</strong> Where subclause 55.4(a) applies, even though the recall is continuous with the next period of ordinary hours, an Employee will be entitled to a minimum three (3) hour payment for the recall at the applicable overtime rates, and payment for the full period of ordinary hours. The Employee will also be entitled without loss of pay to attend to ablution and sustenance matters.</p><p>Plain language terms: OT, extra hours, double time.</p>',14)])])}const f=o(s,[["render",l]]);export{c as __pageData,f as default};
